    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int n; cin>>n;
        vector<int> a(n), b(n);
        for(int &x:a) cin>>x;
        for(int &x:b) cin>>x;
        sort(a.begin(), a.end());
        bool ok = (a==b);
        cout << (ok?"yes":"no") << '\n';
    }
    return 0;
}

